import{Logger}from '../shared/logger.js';class QuickActionsFAB{constructor(options={}){this.options={position: 'bottom-right',showTooltip: true,enableKeyboard: true,animationDuration: 300,actions: [],...options};this.container=null;this.mainButton=null;this.panel=null;this.isExpanded=false;this.actions=[];this.init();}init(){this.createDOM();this.bindEvents();this.registerKeyboardShortcuts();Logger.info('[QuickActions] Initialized');}createDOM(){this.container=document.createElement('div');this.container.className='quick-actions-fab';this.container.setAttribute('role','navigation');this.container.setAttribute('aria-label','Quick actions');this.panel=document.createElement('div');this.panel.className='quick-actions-panel';this.panel.setAttribute('role','menu');this.populateActions();this.mainButton=document.createElement('button');this.mainButton.className='fab-main';this.mainButton.setAttribute('aria-label','Quick actions');this.mainButton.setAttribute('aria-expanded','false');this.mainButton.innerHTML=`<span class="material-symbols-outlined">add</span>${this.options.showTooltip ? '<span class="fab-tooltip">Thao tác nhanh</span>' : ''}`;this.container.appendChild(this.panel);this.container.appendChild(this.mainButton);document.body.appendChild(this.container);}populateActions(){if(!this.options.actions||this.options.actions.length===0){this.options.actions=[{icon: 'add',label: 'Thêm mới',shortcut: 'N',variant: 'primary',onClick:()=>{}},{icon: 'upload',label: 'Upload',shortcut: 'U',variant: 'info',onClick:()=>{}},{icon: 'download',label: 'Download',shortcut: 'D',variant: 'success',onClick:()=>{}},{icon: 'settings',label: 'Cài đặt',shortcut: 'S',variant: 'warning',onClick:()=>{}}];}this.actions=this.options.actions;this.panel.innerHTML='';[...this.actions].reverse().forEach((action,index)=>{const item=document.createElement('button');item.className=`quick-action-item quick-action-item--${action.variant||'primary'}speed-dial-item`;item.setAttribute('role','menuitem');item.setAttribute('data-index',index);item.innerHTML=`<span class="material-symbols-outlined">${action.icon}</span><span class="quick-action-label">${action.label}</span>${action.shortcut ? `<span class="quick-action-shortcut">${action.shortcut}</span>` : ''}`;item.addEventListener('click',()=>this.handleActionClick(index));this.panel.appendChild(item);});if(this.actions.length>0){const label=document.createElement('div');label.className='quick-actions-label';label.textContent='Thao tác';this.panel.appendChild(label);}}bindEvents(){this.mainButton.addEventListener('click',()=>this.toggle());document.addEventListener('click',(e)=>{if(!this.container.contains(e.target)){this.collapse();}});document.addEventListener('keydown',(e)=>{if(e.key==='Escape'&&this.isExpanded){this.collapse();this.mainButton.focus();}});}registerKeyboardShortcuts(){if(!this.options.enableKeyboard)return;document.addEventListener('keydown',(e)=>{if(e.target.tagName==='INPUT'||e.target.tagName==='TEXTAREA'){return;}this.actions.forEach((action,index)=>{if(action.shortcut&&e.key.toUpperCase()===action.shortcut){e.preventDefault();this.handleActionClick(index);}});if(e.altKey&&e.key==='a'){e.preventDefault();this.toggle();}});}toggle(){if(this.isExpanded){this.collapse();}else{this.expand();}}expand(){this.isExpanded=true;this.mainButton.classList.add('is-expanded');this.mainButton.setAttribute('aria-expanded','true');this.panel.classList.add('is-visible');const items=this.panel.querySelectorAll('.speed-dial-item');items.forEach((item,index)=>{setTimeout(()=>{item.classList.add('is-visible');},50+(index*50));});Logger.debug('[QuickActions] Expanded');}collapse(){this.isExpanded=false;this.mainButton.classList.remove('is-expanded');this.mainButton.setAttribute('aria-expanded','false');this.panel.classList.remove('is-visible');const items=this.panel.querySelectorAll('.speed-dial-item');items.forEach((item)=>{item.classList.remove('is-visible');});Logger.debug('[QuickActions] Collapsed');}handleActionClick(index){const action=this.actions[index];if(action&&typeof action.onClick==='function'){action.onClick();this.collapse();Logger.info('[QuickActions] Action clicked:',action.label);}}addAction(action){this.actions.push(action);this.populateActions();Logger.info('[QuickActions] Action added:',action.label);}removeAction(label){const index=this.actions.findIndex(a=>a.label===label);if(index!==-1){this.actions.splice(index,1);this.populateActions();Logger.info('[QuickActions] Action removed:',label);}}destroy(){if(this.container&&this.container.parentNode){this.container.parentNode.removeChild(this.container);}Logger.info('[QuickActions] Destroyed');}}export function initQuickActions(){const existingFAB=document.querySelector('.quick-actions-fab');if(!existingFAB){return new QuickActionsFAB();}return null;}export default QuickActionsFAB;